 static DrawingPath createDrawingPath(BrushPoint p,[double fs=40])=>_finite(p)?DrawingPath([p],'M ${_fp(p)}',fs):DrawingPath([],'',fs);static DrawingPath appendDrawingPoint(DrawingPath path,BrushPoint p){if(!_finite(p)||path.points.isEmpty||_dist(path.points.last,p)<3)return path;final n=[...path.points];if(n.length==1||_turn(n[n.length-2],n.last,p)>=18)n.add(p);else n[n.length-1]=p;return DrawingPath(n,buildRoundedDrawingPath(n,path.fontSize),path.fontSize);}static DrawingPath?_drawing(List<BrushPoint>points,double fs){DrawingPath?path;for(final p in points.where(_finite))path=path==null?createDrawingPath(p,fs):appendDrawingPoint(path,p);return path!=null&&path.points.length>=2?path:null;}
 static double _perp(BrushPoint p,BrushPoint a,BrushPoint b){final dx=b.x-a.x,dy=b.y-a.y,l=dx*dx+dy*dy;if(l==0)return _dist(p,a);final t=_clamp(((p.x-a.x)*dx+(p.y-a.y)*dy)/l,0,1);return _dist(p,BrushPoint(a.x+t*dx,a.y+t*dy));}static List<BrushPoint>_simplify(List<BrushPoint>p,double tol){if(p.length<=2)return p;final keep=List.filled(p.length,false);keep[0]=keep[p.length-1]=true;final stack=<List<int>>[[0,p.length-1]];while(stack.isNotEmpty){final r=stack.removeLast();var best=0.0,index=-1;for(var i=r[0]+1;i<r[1];i++){final d=_perp(p[i],p[r[0]],p[r[1]]);if(d>best){best=d;index=i;}}if(best>tol){keep[index]=true;stack.addAll([[r[0],index],[index,r[1]]]);}}return[for(var i=0;i<p.length;i++)if(keep[i])p[i]];}
 static ArcPath prepareArcLengthPath(List<BrushPoint>input,[double minimum=0.5]){final valid=input.where(_finite).toList(),filtered=<BrushPoint>[];for(final p in valid)if(filtered.isEmpty||_dist(filtered.last,p)>=minimum)filtered.add(p);if(valid.isNotEmpty&&filtered.isNotEmpty&&_dist(filtered.last,valid.last)>0)filtered.add(valid.last);final points=_simplify(filtered,max(minimum*0.5,0.1));final segments=<BrushSegment>[];var total=0.0;for(var i=1;i<points.length;i++){final l=_dist(points[i-1],points[i]);if(l>0){segments.add(BrushSegment(points[i-1],points[i],total,l));total+=l;}}return ArcPath(points,segments,total);}static BrushPoint _pointAt(ArcPath p,double d){if(p.segments.isEmpty)return const BrushPoint(0,0);d=_clamp(d,0,p.totalLength);for(final s in p.segments)if(d<=s.start+s.length){final t=_clamp((d-s.start)/s.length,0,1);return BrushPoint(s.a.x+(s.b.x-s.a.x)*t,s.a.y+(s.b.y-s.a.y)*t);}return p.segments.last.b;}static PathSample sampleAt(ArcPath p,double progress,[double fs=40]){progress=_clamp(progress,0,1);if(p.totalLength<=0)return PathSample(0,0,0,progress);final d=p.totalLength*progress,w=max(min(max(fs*1.1,0.75),p.totalLength*0.06),0.75),a=_pointAt(p,d-w),b=_pointAt(p,d+w),v=_pointAt(p,d);return PathSample(v.x,v.y,atan2(b.y-a.y,b.x-a.x),progress);}
 static String stableRepeatedText(String text,double fs){final p=text.trim();if(p.isEmpty)return '';final chars=CharactersFallback(p).length;final count=min(256,max(16,(20000/max(fs,chars*fs*0.62)).ceil())).toInt();return List.filled(count,p).join('   ');}static String _esc(Object v)=>v.toString().replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&apos;');
 static String renderSvg(Uint8List bytes,String mime,double width,double height,List<BrushPoint>points,String text,[BrushOptions o=const BrushOptions()]){if(!['image/png','image/jpeg','image/webp','image/gif','image/avif'].contains(mime))throw ArgumentError('unsupported MIME');final phrase=text.trim(),fs=o.fontSize.isFinite&&o.fontSize>0?o.fontSize:40.0,path=_drawing(points,fs);if(phrase.isEmpty||path==null)throw ArgumentError('text and two points required');final repeated=o.repeatText?stableRepeatedText(phrase,fs):phrase,gradient=o.magicGradient?'<linearGradient id="brush-gradient" x1="100" y1="150" x2="900" y2="850" gradientUnits="userSpaceOnUse"><stop offset="0%" stop-color="#ec4899"/><stop offset="20%" stop-color="#f97316"/><stop offset="40%" stop-color="#facc15"/><stop offset="60%" stop-color="#10b981"/><stop offset="80%" stop-color="#3b82f6"/><stop offset="100%" stop-color="#8b5cf6"/></linearGradient>':'',shadow=o.shadow?'<filter id="brush-shadow"><feDropShadow dx="0" dy="2" stdDeviation="2" flood-color="#0f172a" flood-opacity="0.65"/></filter>':'',filter=o.shadow?' filter="url(#brush-shadow)"':'',fill=o.magicGradient?'url(#brush-gradient)':_esc(o.color),spacing=o.letterSpacing??max(0.75,fs*0.06),reveal=_clamp(o.revealProgress,0,1),d=_esc(path.d);return '<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${_fmt(width)}" height="${_fmt(height)}" viewBox="0 0 ${_fmt(width)} ${_fmt(height)}"><image width="${_fmt(width)}" height="${_fmt(height)}" preserveAspectRatio="xMidYMid slice" href="data:$mime;base64,${base64Encode(bytes)}"/><defs><path id="brush-path" d="$d"/>$gradient$shadow<mask id="brush-reveal"><rect width="100%" height="100%" fill="black"/><path d="$d" pathLength="1" fill="none" stroke="white" stroke-width="${_fmt(fs*2.4)}" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="1" stroke-dashoffset="${_fmt(1-reveal)}"/></mask></defs><g mask="url(#brush-reveal)" opacity="${_fmt(_clamp(o.opacity,0,1))}"$filter><text font-family="${_esc(o.fontFamily)}" font-size="${_fmt(fs)}" font-weight="${_esc(o.fontWeight)}" letter-spacing="${_fmt(spacing)}" fill="$fill" stroke="${_esc(o.strokeColor)}" stroke-width="${_fmt(max(0,o.strokeWidth).toDouble())}" paint-order="stroke fill"><textPath href="#brush-path" xlink:href="#brush-path" startOffset="0" spacing="exact">${_esc(repeated)}</textPath></text></g></svg>\n';}
